/**
 * opendyslexic-font.ts
 *
 * Self-contained OpenDyslexic webfont (Regular + Bold), embedded as base64
 * woff2 `data:` URIs so the dyslexia-friendly face is GUARANTEED to render even
 * when the visitor does not already have it installed — with NO third-party
 * request (privacy: nothing leaks the visitor's IP/UA to a font CDN) and NO
 * extra serving infrastructure.
 *
 * Subsetting: the upstream faces are ~115-120 KB each. We subset to the Latin
 * ranges actually needed for Latin-script pages (Basic Latin, Latin-1
 * Supplement, Latin Extended-A, plus common smart-quotes/dashes/euro), which
 * covers en/es/fr/de and most Western-European host pages, bringing each face
 * to ~25 KB. Non-Latin pages simply fall back to the CSS font stack — the
 * honest behaviour, since OpenDyslexic is a Latin-only face.
 *
 * The bytes live in THIS dedicated module (kept out of effects.ts to keep that
 * file readable) and are only injected into the host page on first activation
 * of the readable-font feature (see `ensureDyslexiaFont` in effects.ts), so the
 * font is never fetched/decoded unless the user turns the feature on.
 *
 * FONT LICENSE — OpenDyslexic is (c) the OpenDyslexic project, licensed under
 * the SIL Open Font License v1.1 (https://opendyslexic.org,
 * https://github.com/antijingoist/opendyslexic). The OFL expressly permits
 * embedding and redistribution. The faces are unmodified apart from glyph
 * subsetting (which the OFL allows), and the Reserved Font Name "OpenDyslexic"
 * is retained for the original design.
 */

/* eslint-disable */
export const OPENDYSLEXIC_REGULAR_WOFF2 =
  "data:font/woff2;base64,";

export const OPENDYSLEXIC_BOLD_WOFF2 =
  "data:font/woff2;base64,";
